<?php ob_start(); ?>
<section class="ce-card"><h1><?= htmlspecialchars($title, ENT_QUOTES, 'UTF-8') ?></h1><table class="ce-table"><thead><tr><th>Тема</th><th>Версия</th><th>Статус</th><th></th></tr></thead><tbody><?php foreach ($themes as $slug => $theme): ?><tr><td><strong><?= htmlspecialchars($theme->manifest['name'] ?? $slug, ENT_QUOTES, 'UTF-8') ?></strong><br><small><?= htmlspecialchars($theme->manifest['description'] ?? '', ENT_QUOTES, 'UTF-8') ?></small></td><td><?= htmlspecialchars($theme->manifest['version'] ?? 'dev', ENT_QUOTES, 'UTF-8') ?></td><td><?= $slug === $active ? 'Активна' : 'Не активна' ?></td><td><a href="/admin/themes/<?= urlencode($slug) ?>/preview">Preview</a><?php if ($slug !== $active): ?><form method="post" action="/admin/themes/<?= urlencode($slug) ?>/activate" style="display:inline"><button type="submit">Активировать</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></section>
